using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch)
        return false;

    // Get sketch health state
    adsk::fusion::FeatureHealthStates health = sketch->healthState();
    if (health == adsk::fusion::FeatureHealthStates::ErrorFeatureHealthState ||
        health == adsk::fusion::FeatureHealthStates::WarningFeatureHealthState)
    {
        std::string msg = sketch->errorOrWarningMessage();
    }

    // Get sketch texts
    Ptr sketchPoints = sketch->sketchPoints();
    if (!sketchPoints)
        return false;

    // Create sketch point
    Ptr point = Point3D::create(1.0, 1.0, 0);
    Ptr sketchPoint = sketchPoints->add(point);
    if (!sketchPoint)
        return false;

    // Move sketch point
    Ptr translation = Vector3D::create(1.0, 0.0, 0.0);
    sketchPoint->move(translation);

    return true;
}
